INSERT INTO public.photos VALUES (22538, 'Plaza de Aragâ”œâ”‚n 1972', 'Trolebâ”œâ•‘s de la lâ”œÂ¡nea "Ciudad Jardâ”œÂ¡n" en la Plaza de Aragâ”œâ”‚n, yendo hacia la Terminal de la Lâ”œÂ¡nea, situada en la Plaza de Santa Engracia. Esta lâ”œÂ¡nea fue clausurada en octubre de 1975. Fuente visual: www.flickr.com/photos/jhm0284/5812542337/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64825600, -0.88471500, '0101000020E610000001FBE8D4954FECBFC8B7770DFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14868792646.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14868792646.webp', 'https://www.flickr.com/photos/zaragozaantigua/14868792646/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22593, 'Plaza de Aragâ”œâ”‚n 1972', 'Un 200 de la lâ”œÂ¡nea 11 en la plaza de Aragâ”œâ”‚n, camino de Parque. Al fondo, por encima del edificio de Capitanâ”œÂ¡a, el moderno remate del chaflâ”œÃ­n entre paseo Pamplona-Doctor Cerrada, empleado como atalaya publicitaria de ingenios electrâ”œâ”‚nicos. Justo detrâ”œÃ­s del tranvâ”œÂ¡a, interesante visual del antiguo hotelito del nâ”¬â•‘ 10 de la plaza, en su segunda versiâ”œâ”‚n formal, entre Capitanâ”œÂ¡a y Canfranc. A su derecha, caâ”œâ–’izos de obra que anuncian erecciâ”œâ”‚n de nuevo edificio torril despersonalizado sobre el solar del ya piqueteado hotelito nâ”¬â•‘ 11 de la plaza. Fuente visual: www.flickr.com/photos/jhm0284/5813112116/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64856000, -0.88505300, '0101000020E6100000074147AB5A52ECBF34BF9A0304D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16674031758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16674031758.webp', 'https://www.flickr.com/photos/zaragozaantigua/16674031758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22621, 'P.â”¬â•‘ de Pamplona 1977', 'Inmueble esquinero entre el paseo de Pamplona y la calle de Bilbao, proyectado por Julio Bravo Folch a comienzos del siglo XX, cerca de la Escuela de Comercio y el convento-colegio de las Esclavas del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s. Al poco tiempo se le anexâ”œâ”‚ un nuevo edificio de viviendas de alquiler, a la derecha de la imagen, diseâ”œâ–’ado por Marcelino Secorum. Mâ”œÃ­s tarde, a la Escuela le sucediâ”œâ”‚ un nuevo bloque en los aâ”œâ–’os 50, y las Esclavas se trasladaron a finales de los aâ”œâ–’os 60. Este edificio, y su anexo de la derecha, fueron objeto de una transformaciâ”œâ”‚n a la zaragozana en los aâ”œâ–’os 80.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64848000, -0.88639400, '0101000020E610000027DC2BF3565DECBF170E846401D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19776210025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19776210025.webp', 'https://www.flickr.com/photos/zaragozaantigua/19776210025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22671, 'Plaza de Aragâ”œâ”‚n 1970', 'La metamorfosis del paseo de la Independencia, tras su imposiciâ”œâ”‚n como autopista, impulsâ”œâ”‚ por simpatâ”œÂ¡a la mudanza de algunos edificios que la flanqueaban, desde la plaza de Espaâ”œâ–’a, hasta la plaza de Paraâ”œÂ¡so. Asâ”œÂ¡, la plaza de Aragâ”œâ”‚n comenzâ”œâ”‚ a padecer su particular "transiciâ”œâ”‚n" edilicia, que en la imagen queda dramâ”œÃ­ticamente constrastada entre los luminosos, modernos y atractivos bloques, y las oscuras, viejas y tenebrosas casonas que afeaban el entorno, y bien poco ayudaban a la imagen de una ciudad como la nueva Zaragoza del milagro (econâ”œâ”‚mico). Esta falla serâ”œÂ¡a enmendada, prâ”œÃ­cticamente, en la dâ”œÂ®cada siguiente. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64841500, -0.88489300, '0101000020E6100000D1B2EE1F0B51ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24119327112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24119327112.webp', 'https://www.flickr.com/photos/zaragozaantigua/24119327112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22735, 'Plaza Aragâ”œâ”‚n 1972', 'Confluencia de varios medios de transporte en la plaza de Aragâ”œâ”‚n, con el edificio de Capitanâ”œÂ¡a al fondo a la derecha. A la izquierda, la unidad 55 de la lâ”œÂ¡nea de trolebâ”œâ•‘s "Ciudad Jardâ”œÂ¡n" se dirige a su parada en la plaza de Santa Engracia. A la derecha, un taxi de la flota local. Fuente: Colecciâ”œâ”‚n Daniel Andrâ”œÂ®s.', 1972, 1972, 1972, 'Anos 70', 'CENTRO', 41.64834900, -0.88470100, '0101000020E6100000C2A1B778784FECBF79B29B19FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31260366451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31260366451.webp', 'https://www.flickr.com/photos/zaragozaantigua/31260366451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
