INSERT INTO public.photos VALUES (22739, 'Plaza de Aragâ”œâ”‚n 1977', 'Imagen centrada en la cobertura de obra reciâ”œÂ®n instalada sobre el edificio del antiguo nâ”¬â•‘ 10 de la plaza de Aragâ”œâ”‚n, en proceso de homologarse a su vecino del nâ”¬â•‘ 11, al otro lado de la calle de Canfranc, ya procesado unos pocos aâ”œâ–’os antes. A su izquierda, el edificio de Capitanâ”œÂ¡a. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.64855400, -0.88536300, '0101000020E610000091D442C9E454ECBF51D845D103D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31563726650.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31563726650.webp', 'https://www.flickr.com/photos/zaragozaantigua/31563726650/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22744, 'P.â”¬â•‘ de Pamplona 1970', 'Imagen posiblemente capturada en el desfile de carrozas artâ”œÂ¡sticas del denominado "Coso Blanco", durante las Fiestas de la Primavera de ese aâ”œâ–’o. La desbordante alegrâ”œÂ¡a del pâ”œâ•‘blico contagia a las muchachas ataviadas con vestidos neoregionalistas, en un escenario plagado de barrocas y seriadas representaciones del fâ”œÂ®lido icono de la ciudad, delante de la antigua fachada del nâ”¬â•‘ 2 del paseo, chaflanero con la calle de Bilbao. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'CENTRO', 41.64854600, -0.88647900, '0101000020E6100000B4E73235095EECBFCFF9298E03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32192727064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32192727064.webp', 'https://www.flickr.com/photos/zaragozaantigua/32192727064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22855, 'Grâ”œâ•‘a municipal 1983', 'Una mula, que al parecer impide el eficaz desenvolvimiento del trâ”œÃ­fico rodado, es retirada por la grâ”œâ•‘a municipal para llevarla a los depâ”œâ”‚sitos de vehâ”œÂ¡culos requisados. La escena se produce en pleno centro de la ciudad, en la plaza de Aragâ”œâ”‚n. El servicio de grâ”œâ•‘as de la policâ”œÂ¡a municipal, luego local, fue aumentado hasta las 10 unidades al aâ”œâ–’o siguiente. Ya en 1990, entrâ”œâ”‚ en funcionamiento el nuevo depâ”œâ”‚sito de vehâ”œÂ¡culos en la carretera de Castellâ”œâ”‚n, ademâ”œÃ­s de las nuevas instalaciones de caballerâ”œÂ¡a. Por fin, en 1995, el servicio fue privatizado, acabando por convertir a Zaragoza en la ciudad espaâ”œâ–’ola con la tasa mâ”œÃ­s alta de devoluciâ”œâ”‚n de vehâ”œÂ¡culos. A la izquierda, marquesina con publicidad de una omnipresente entidad de ahorro local, que pronto cambiarâ”œÂ¡a de imagen corporativa. A la derecha, sobre el adoquinado firme por donde circularan tranvâ”œÂ¡as, un autobâ”œâ•‘s urbano.', 1983, 1983, 1983, 'Anos 80', 'CENTRO', 41.64855100, -0.88471200, '0101000020E6100000BD1E4C8A8F4FECBFE0641BB803D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15523578107.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15523578107.webp', 'https://www.flickr.com/photos/zaragozaantigua/15523578107/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23051, 'Vista 1992', 'Imagen capturada desde la altura del Edificio Elâ”œÂ¡seos con una vista que desde la moderna fuente cibernâ”œÂ®tica de la plaza de Basilio Paraâ”œÂ¡so, en primer tâ”œÂ®rmino, y pasando por la plaza de Aragâ”œâ”‚n y el paseo de la Independencia, alcanza hasta la plaza de Espaâ”œâ–’a, al fondo. Esta zona seguâ”œÂ¡a siendo una gran cicatriz automovilâ”œÂ¡stica abierta en el corazâ”œâ”‚n del centro urbano, mientras el Plan de Trâ”œÃ­fico vigente planteaba en tâ”œÂ®rminos de "inundaciâ”œâ”‚n" y "congestiâ”œâ”‚n" la situaciâ”œâ”‚n de la movilidad en Zaragoza. Todavâ”œÂ¡a era tiempo de soluciones mâ”œÃ­s cosmâ”œÂ®ticas que efectivas.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.64851200, -0.88502100, '0101000020E61000002FBE688F1752ECBF2288F37002D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50443752333.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50443752333.webp', 'https://www.flickr.com/photos/zaragozaantigua/50443752333/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23267, 'Torre del Pino 1808', '"Alarma en la Torre del Pino. En donde se distinguieron los Patriotas rechazando a los Franceses el dâ”œÂ¡a 4 de Agosto de 1808: en este encuentro muriâ”œâ”‚ el comandante de armas D. Antonio Cuadros". Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. Esta estampa representa la acciâ”œâ”‚n del 4 de agosto de 1808 en la denominada Torre del Pino, propiedad de las carmelitas descalzas de San Josâ”œÂ®, en lo que mâ”œÃ­s tarde serâ”œÂ¡a el Gobierno Militar en la calle del Marquâ”œÂ®s de Casa-Jimâ”œÂ®nez (espacio que limitan actualmente esta calle y las de Bilbao, Ponzano, Canfranc). La câ”œâ•‘pula con dos pequeâ”œâ–’as torres del fondo es la iglesia de San Fernando. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.64908600, -0.88549700, '0101000020E61000007898F6CDFD55ECBF4E25034015D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15080226208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15080226208.webp', 'https://www.flickr.com/photos/zaragozaantigua/15080226208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23645, 'Capitanâ”œÂ¡a General c.1908', 'AHPZ. Estudio Coyne. Ca. 1908 "Capitanâ”œÂ¡a General."', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15822955885.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15822955885.webp', 'https://www.flickr.com/photos/zaragozaantigua/15822955885/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
