INSERT INTO public.photos VALUES (23648, 'Calle Soberanâ”œÂ¡a Nacional 1920', 'Imagen, a la izquierda, de la monumental fachada principal del Cuartel de Artillerâ”œÂ¡a de El Carmen, en la calle de la Soberanâ”œÂ¡a Nacional. Su denominaciâ”œâ”‚n provenâ”œÂ¡a del antiguo convento del Carmen de los PP. Carmelitas Calzados. Por aquâ”œÂ¡ pasa en doble vâ”œÂ¡a la Lâ”œÂ¡nea de Madrid del tranvâ”œÂ¡a, que une la plaza de la Constituciâ”œâ”‚n con la Estaciâ”œâ”‚n de Madrid. En este Cuartel se produjo, en enero de 1920, una sublevaciâ”œâ”‚n interna enmarcada en los graves conflictos sociales de la â”œÂ®poca, y que terminâ”œâ”‚ con la muerte de diez personas, tres durante los hechos, y siete fusilados despuâ”œÂ®s. Tuvo enorme resonancia incluso en medios de informaciâ”œâ”‚n de carâ”œÃ­cter estatal, y fue convenientemente instrumentalizado para justificar el posterior golpe de estado de Primo de Rivera (con la anuencia del rey), entre cuyos objetivos estaba "restablecer la paz social". En la imagen, la calle Soberanâ”œÂ¡a Nacional continuaba, al fondo y hacia la izquierda, hasta llegar a la Puerta del Carmen. La fotografâ”œÂ¡a se ha tomado desde la Plaza del Pueblo. Fuente visual: Fotos Alonso, Revista Nuevo Mundo', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65099800, -0.88467800, '0101000020E6100000B7B3AF3C484FECBF76E107E753D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19126035736.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19126035736.webp', 'https://www.flickr.com/photos/zaragozaantigua/19126035736/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23658, 'Cuartel del Carmen c.1955', 'Imagen en altura desde el nâ”¬â•‘ 2 de la calle Capitâ”œÃ­n Portolâ”œÂ®s (antigua de Soberanâ”œÂ¡a Nacional) del Cuartel del Carmen recayente a dicha calle, y a la calle de la Vieja Guardia (antes integrante de la calle Casa Jimâ”œÂ®nez), a la izquierda, que desemboca en el edificio del Gobierno Militar, que fuera antiguo convento de las Carmelitas Descalzas de San Josâ”œÂ®. Al fondo, destaca en altura el gran Frontâ”œâ”‚n Aragonâ”œÂ®s de la calle Albareda y, a la derecha, el reciente bloque del final de la calle Canfranc. Otro entraâ”œâ–’able recuerdo de que en Zaragoza muchos nombres de sus viales son una interesante antâ”œÂ¡tesis de las cosas que son asâ”œÂ¡ "de toda la vida". Este Cuartel del Carmen fue desmantelado tiempo despuâ”œÂ®s, y vendido su solar. Parte del dinero conseguido fue utilizado para la construcciâ”œâ”‚n del nuevo Hospital Militar, en Casablanca. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.65087900, -0.88485900, '0101000020E6100000CB4752D2C350ECBF9C53C90050D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22943862904.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22943862904.webp', 'https://www.flickr.com/photos/zaragozaantigua/22943862904/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23669, 'Plaza de Aragâ”œâ”‚n 1982', 'Candidatos sobre las vallas de obra que delimitan el solar donde estuviera el hotelito del nâ”¬â•‘ 10 de la plaza de Aragâ”œâ”‚n, diseâ”œâ–’ado por Fernando de Yarza con aportaciones tâ”œÂ®cnicas de Ricardo Magdalena, construido en 1887 y reformado luego. Casi un siglo despuâ”œÂ®s, este espacio serâ”œÂ¡a contenedor de otra muestra de la flamante y descontextualizada arquitectura moderna que caracteriza la plaza. A la izquierda, el edificio de la Capitanâ”œÂ¡a General y a la derecha el inmueble del nâ”¬â•‘ 16 de la calle de Ponciano Ponzano. En primer tâ”œÂ®rmino cohabitan carteles publicitarios que hacen alusiâ”œâ”‚n a la campaâ”œâ–’a electoral de las elecciones generales de octubre de ese aâ”œâ–’o. Entre ellos, el de la candidatura encabezada por Manuel Fraga Iribarne de la coaliciâ”œâ”‚n formada por Alianza Popular, Partido Demâ”œâ”‚crata Popular, y partidos regionalistas de derecha, como el PAR; y el de la candidatura encabezada por Felipe Gonzâ”œÃ­lez Mâ”œÃ­rquez, del PSOE. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1982, 1982, 1982, 'Anos 80', 'CENTRO', 41.64855400, -0.88536300, '0101000020E610000091D442C9E454ECBF51D845D103D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31969575076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31969575076.webp', 'https://www.flickr.com/photos/zaragozaantigua/31969575076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23673, 'Cuartel del Carmen 1920', 'Imagen del patio del cuartel de artillerâ”œÂ¡a del Carmen, escenario de un invernal intento de sublevaciâ”œâ”‚n armada protagonizado por media docena de soldados, que terminâ”œâ”‚ en fracaso. Tras los arcones de municiones de primer plano, y al fondo, fueron fusilados los voluntaristas rebeldes de acuerdo con el Câ”œâ”‚digo de Justicia Militar vigente. En el pabellâ”œâ”‚n de la derecha estaba el ingreso principal al cuartel, desde la calle de la Soberanâ”œÂ¡a Nacional. Las traseras del de la izquierda limitaban con el edificio de la Escuela de Veterinaria, recayente a esa misma calle, frente al convento de la Encarnaciâ”œâ”‚n. Fuente visual: foto Alonso, en Mundo Grâ”œÃ­fico.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.65083900, -0.88526700, '0101000020E61000000A4CA7751B54ECBF0DFB3DB14ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33473608256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33473608256.webp', 'https://www.flickr.com/photos/zaragozaantigua/33473608256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23676, 'Soberanâ”œÂ¡a Nacional 1933', 'Imagen de la calle de la Soberanâ”œÂ¡a Nacional con una buena perspectiva del enorme cuartel de artillerâ”œÂ¡a del Carmen. La captura se ha realizado desde el final de la calle de Ramâ”œâ”‚n y Cajal, hacia donde se dirige por la izquierda el tendido tranviario de la lâ”œÂ¡nea de Madrid. Al fondo, la plaza del Pueblo. En la esquina del muro cuartelario quedan huellas de la lâ”œÃ­pida que durante la dictadura de Primo de Rivera (1926) escenificâ”œâ”‚ el cambio de denominaciâ”œâ”‚n de la calle por la de General Sanjurjo. La llegada de la democracia durante la Segunda Repâ”œâ•‘blica supuso la reposiciâ”œâ”‚n del nombre del vial, hasta que la soberanâ”œÂ¡a nacional fue violentada por las armas facciosas tras el 18 de julio de 1936. A la derecha de la imagen, fuera de plano, y en direcciâ”œâ”‚n a la Puerta del Carmen se ubicaba la antigua casa-cuartel de la Guardia civil, y el ruinoso inmueble de la Escuela Superior de Veterinaria. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.65097600, -0.88597500, '0101000020E6100000EE5A423EE859ECBF8E3D7B2E53D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36673668205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36673668205.webp', 'https://www.flickr.com/photos/zaragozaantigua/36673668205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23688, 'Plaza de Aragâ”œâ”‚n, 1936', 'El general Millâ”œÃ­n Astray durante su estancia en Zaragoza el 26 de agosto programada dentro de una ronda de visitas de altos jerarcas golpistas a las principales ciudades donde habâ”œÂ¡a triunfado la sublevaciâ”œâ”‚n armada contra la democracia republicana. En la imagen inâ”œÂ®dita este general sale en coche de la sede de la 5â”¬Â¬ Divisiâ”œâ”‚n Orgâ”œÃ­nica sita en el nâ”¬â•‘ 9 de la plaza de Aragâ”œâ”‚n para dirigirse al cuartel de caballerâ”œÂ¡a de Castillejos donde inspeccionar las fuerzas de caballerâ”œÂ¡a y milicias de Falange.', 1936, 1936, 1936, 'Anos 30', 'CENTRO', 41.64820800, -0.88568600, '0101000020E610000042CD902A8A57ECBFB680D07AF8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51164511510.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51164511510.webp', 'https://www.flickr.com/photos/zaragozaantigua/51164511510/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24135, 'Salâ”œâ”‚n de Pignatelli 1875', '"Plano de los solares en venta procedentes de la Exposiciâ”œâ”‚n Aragonesa y terrenos adyacentes, en Zaragoza", Segundo Dâ”œÂ¡az, 1875. Planta del entorno de la actual plaza de Aragâ”œâ”‚n, con la planificaciâ”œâ”‚n de su desarrollo urbanâ”œÂ¡stico tras la Exposiciâ”œâ”‚n Aragonesa de 1868 en esa ubicaciâ”œâ”‚n. Incluye superficie y precio de cada nuevo solar. Fuente: AMZ.', 1875, 1875, 1875, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19367940539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19367940539.webp', 'https://www.flickr.com/photos/zaragozaantigua/19367940539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24433, 'Ruinas de la iglesia del Carmen 1808', 'Imagen de la aguada sobre papel verjurado realizada en 1812 y que representa las ruinas del interior de la iglesia del convento de Nuestra Seâ”œâ–’ora del Carmen, en este caso en una vista desde el sotocoro hacia el lado de la Epâ”œÂ¡stola, que fue considerada una de las ruinas mâ”œÃ­s emblemâ”œÃ­ticas producidas como consecuencia del primero de los dos asedios franceses de la ciudad en 1808-1809, que supuso la ruina de la gran iglesia de este convento barroco.', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65076500, -0.88521400, '0101000020E610000054C37E4FAC53ECBFD3307C444CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54386789164.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54386789164.webp', 'https://www.flickr.com/photos/zaragozaantigua/54386789164/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24868, 'Plaza de Aragâ”œâ”‚n 1974', 'Inâ”œÂ®dita imagen capturada en la plaza de Aragâ”œâ”‚n y centrada en uno de los modernos "postes de parada" reciâ”œÂ®n instalados por la empresa Los Tranvâ”œÂ¡as de Zaragoza, S.A. en las paradas mâ”œÃ­s câ”œÂ®ntricas de los autobuses urbanos, como esta. El elemento mâ”œÃ­s novedoso radicaba en la informaciâ”œâ”‚n que proporcionaba sobre la lâ”œÂ¡nea o lâ”œÂ¡neas que allâ”œÂ¡ paraban, y los itinerarios que realizaban. En este caso, este poste indicaba la parada de las lâ”œÂ¡neas 21 (Plaza del Pilar-Barrio de Oliver), 32 (Cuâ”œÂ®llar-Delicias), 33 (Portillo-Pinares de Venecia) y 34 (Plaza de Espaâ”œâ–’a-Cementerio). Las tres â”œâ•‘ltimas lâ”œÂ¡neas eran un calco del servicio que proporcionaron las lâ”œÂ¡neas del tranvâ”œÂ¡a 5 y 8, pero en autobâ”œâ•‘s era considerado menos provinciano. Al fondo, un trolebâ”œâ•‘s de dos pisos de la lâ”œÂ¡nea Ciudad Jardâ”œÂ¡n se dirige a la terminal de la plaza de Santa Engracia. Esta lâ”œÂ¡nea serâ”œÂ¡a clausurada al aâ”œâ–’o siguiente. Tras â”œÂ®l emerge el bloque del nâ”¬â•‘ 7 de la plaza, el segundo en ser construido a finales de los aâ”œâ–’os 60 sobre el antiguo "hotelito" del mismo nâ”œâ•‘mero.', 1974, 1974, 1974, 'Anos 70', 'CENTRO', 41.64877700, -0.88509600, '0101000020E6100000D940BAD8B452ECBFD1B2EE1F0BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51644006454.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51644006454.webp', 'https://www.flickr.com/photos/zaragozaantigua/51644006454/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24870, 'Pâ”¬â•‘ de Pamplona 1915', 'Imagen capturada en el paseo de Pamplona durante el transcurso de la cabalgata organizada por el Centro Industrial durante las fiestas del Pilar del aâ”œâ–’o 1915 que recorriâ”œâ”‚ las principales calles del centro, integrada por una sucesiâ”œâ”‚n de carrozas que representaban a algunos importantes comerciantes, fabricantes e industriales de la ciudad, ademâ”œÃ­s de a la propia comisiâ”œâ”‚n de festejos y al Ayuntamiento. La de la imagen se corresponde con la carroza "estilo Luis XV" compuesta con el patrocinio del industrial chocolatero Joaquâ”œÂ¡n Orâ”œâ•‘s y que consiguiâ”œâ”‚ el tercer premio. Aparece estacionada ante la fâ”œÃ­brica de conservas de Marraco.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64820000, -0.88652300, '0101000020E61000009CDB847B655EECBF34A2B437F8D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53458710901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53458710901.webp', 'https://www.flickr.com/photos/zaragozaantigua/53458710901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25201, 'Monumento a Ramâ”œâ”‚n de Pignatelli 1860', 'Glorieta de Pignatelli, con el monumento a Ramâ”œâ”‚n de Pignatelli, obra de Antonio Josâ”œÂ® Palao, inaugurado el 24 de junio de 1859, en conmemoraciâ”œâ”‚n del aniversario del Canal Imperial de Aragâ”œâ”‚n. Al fondo, la torre de la iglesia de Santa Engracia. Fuente visual: Mariano Jâ”œâ•‘dez y Ortiz. â”œÃ¼lbum de Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Colecciâ”œâ”‚n Mariano Martâ”œÂ¡n Casalderrey. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.64823300, -0.88485300, '0101000020E6100000438F183DB750ECBF0F98874CF9D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710371517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710371517.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710371517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25202, 'Plaza de Aragâ”œâ”‚n 1960', 'Câ”œÂ®sar Gracia Jarque. 1960. "Plaza de Aragâ”œâ”‚n". Vista panorâ”œÃ­mica de buena parte de la Plaza de Aragâ”œâ”‚n, muy arbolada, y chaleteada. Por detrâ”œÃ­s, despunta el Colegio de los PP. Jesuitas, y su contingente nueva Iglesia. A la derecha, la Plaza de Paraâ”œÂ¡so, y la inmediata subida por el Paseo del General Mola.', 1960, 1960, 1960, 'Anos 60', 'CENTRO', 41.64867300, -0.88487600, '0101000020E61000004E7D2079E750ECBF2C6684B707D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794033309.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794033309.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794033309/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
