INSERT INTO public.photos VALUES (25206, 'Plaza de Aragâ”œâ”‚n 1945', 'AHPZ. Archivo Estudio Coyne. Sobre el solar nâ”¬â•‘ 2 de la manzana "C" de la Expo de 1868 se levantâ”œâ”‚ en 1888, proyectado por Antonio Miranda, un hotelito para Orencio Castellano. En 1916 y 1925 se reforma y amplâ”œÂ¡a, entonces ya propiedad de Luis Pâ”œÂ®rez Cistuâ”œÂ®. En 1944, para el mismo propietario, tiene lugar otra reforma y ampliaciâ”œâ”‚n, tanto horizontal, como vertical, hasta dejarlo como ha llegado a nuestros dâ”œÂ¡as. De resultas de ello, el edificio es definido como eclâ”œÂ®ctico, con elementos clasicistas, racionalistas, y regionalistas. En la imagen, el edificio tras su reforma de 1944, en una Plaza de Aragâ”œâ”‚n aâ”œâ•‘n territorio hotelito. En la actualidad es el â”œâ•‘nico superviviente, como restaurante de luxe.', 1945, 1945, 1945, 'Anos 40', 'CENTRO', 41.64895300, -0.88504300, '0101000020E610000024B891B24552ECBF0FD253E410D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15318086359.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15318086359.webp', 'https://www.flickr.com/photos/zaragozaantigua/15318086359/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25626, 'Romareda 1970', 'Imagen del nuevo polâ”œÂ¡gono Gran Vâ”œÂ¡a, ya redenominado "Romareda", en plena ebulliciâ”œâ”‚n edilicia. La captura se ha realizado desde el ancho vial de nombre Eduardo Ibarra, con un vistazo hacia el suroeste. En primer plano, de izquierda a derecha, las torres de los nâ”œâ•‘meros 6 y 4 de la que luego serâ”œÂ¡a nueva calle Juan II de Aragâ”œâ”‚n, y la torre nâ”¬â•‘ 15 de la prolongaciâ”œâ”‚n de la calle de Asâ”œÂ¡n y Palacios. Detrâ”œÃ­s de ellas, distintos momentos constructivos de otros edificios poligoneros. El panorama estâ”œÃ­ aâ”œâ•‘n tan despejado que es posible, incluso, ver todavâ”œÂ¡a los mâ”œÃ­s veteranos bloques del arranque de la Vâ”œÂ¡a de la Hispanidad, al fondo, a la izquierda. Fuente visual: foto Gerardo Sancho Ramo, AMZ.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63650200, -0.90367900, '0101000020E61000009D9FE238F0EAECBF57EBC4E578D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32841092572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32841092572.webp', 'https://www.flickr.com/photos/zaragozaantigua/32841092572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25208, 'Salâ”œâ”‚n de Pignatelli c.1877', 'Inaugurado en 1859, este gran bulto redondo del orondo Pignatelli fue elemento central en la Primera Exposiciâ”œâ”‚n Aragonesa (setiembre-noviembre 1868), ubicada en el novâ”œÂ¡simo recinto del Salâ”œâ”‚n de Pignatelli (antes, Prado de San Jerâ”œâ”‚nimo). A pesar de que el Palacio de la Exposiciâ”œâ”‚n (edificio principal de la misma), habâ”œÂ¡a sido erigido con la intenciâ”œâ”‚n de que permaneciera, y fuera el pionero de una pronta urbanizaciâ”œâ”‚n de la virgen zona, la penuria econâ”œâ”‚mica municipal hizo que fuera piqueteado para vender el suelo que ocupaba, aunque el proceloso proceso de urbanizaciâ”œâ”‚n se extenderâ”œÂ¡a hasta entrado el siglo XX, marcado siempre por los intereses particulares de los propietarios del suelo. Cosas de emprendedores, que funcionaban asâ”œÂ¡. Tal que ahora. De haberse mantenido, ese Palacio hubiera definido una nueva traza de la plaza, pues estaba justo en medio de la actual calle Canfranc, y hubiera lucido justo a la derecha del antiguo edificio de Capitanâ”œÂ¡a. En la imagen, la estatua de Pignatelli en el despejado entorno de la glorieta a la que daba nombre. A su izquierda, los edificios del "Parque de Ingenieros", que desde 1861 estaba ubicado en el antiguo convento de las Carmelitas Descalzas de San Josâ”œÂ®, del que se conservaba la iglesia, el claustro, bodegas... Luego serâ”œÃ­ sede del Gobierno Militar de Zaragoza. La "Operaciâ”œâ”‚n Cuarteles" de los aâ”œâ–’os 70 del pasado siglo lo convertirâ”œÃ­ en propiedad municipal. Tras la estatua, en el centro, los edificios de la calle de la Independencia se proyectan hacia la plaza de la Constituciâ”œâ”‚n, comenzando con el reciente "Teatro de Novedades" (1864). Quâ”œÂ® lejos quedaba Zaragoza, allâ”œÃ­ al fondo...', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64827100, -0.88482300, '0101000020E610000099F4F7527850ECBFFDF84B8BFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16296666795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16296666795.webp', 'https://www.flickr.com/photos/zaragozaantigua/16296666795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25209, 'Calle Ponzano 8, 1897', 'Edificio de la fâ”œÃ­brica de espejos "La Veneciana", de Basilio Paraâ”œÂ¡so, en la calle Ponciano Ponzano 8. La tienda se encontraba en la calle del Coso 6. Se anunciaba ofreciendo "Decorado de iglesias, salones y fachadas. Talla y marqueterâ”œÂ¡a en toda clase de maderas, cartâ”œâ”‚n, pasta y piedra. Persianas. Cromos, oleografâ”œÂ¡a y estampas en litografâ”œÂ¡a, lunas y cristales. Vidrios planos de muselinas y colores. Diamantes para cortarlos". La fâ”œÃ­brica habâ”œÂ¡a estado en la plaza de Santa Engracia (1876-1880), y a partir de 1897 en el Camino de los Cubos. Fuente: Mâ”¬Â¬ Pilar Biel Ibâ”œÃ­â”œâ–’ez, Zaragoza y la industrializaciâ”œâ”‚n: la arquitectura industrial 1875-1936, IFC, 2004.', 1897, 1897, 1897, 'Siglo XIX', 'CENTRO', 41.64924900, -0.88521500, '0101000020E61000006BB75D68AE53ECBFF8FA5A971AD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19804027945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19804027945.webp', 'https://www.flickr.com/photos/zaragozaantigua/19804027945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25210, 'Plaza de Aragâ”œâ”‚n c.1955', 'Foto: Josâ”œÂ® Antonio Duce. Imagen nocturna de la plaza de Aragâ”œâ”‚n de Zaragoza. Fuente: rafaelcastillejo.com', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64855100, -0.88471200, '0101000020E6100000BD1E4C8A8F4FECBFE0641BB803D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20719568641.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20719568641.webp', 'https://www.flickr.com/photos/zaragozaantigua/20719568641/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25211, 'Torre del Pino 1865', 'Plano de la Torre del Pino, Antonio Berbegal, Zaragoza, 1865. Detalle de las plantaciones del vivero municipal de la Torre del Pino. Estos terrenos estaban situados entre las actuales calles de Bilbao y Ponciano Ponzano. A la izquierda, el ramal de la acequia de la Romareda que llegaba hasta allâ”œÂ¡; abajo, un pequeâ”œâ–’o tramo del actual paseo de Pamplona. En poco tiempo, las plantaciones serâ”œÃ­n sustituidas por el edificio principal de la Exposiciâ”œâ”‚n Aragonesa de 1868. Fuente: AMZ', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.64827900, -0.88635300, '0101000020E610000082C476F7005DECBF80D767CEFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21055742855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21055742855.webp', 'https://www.flickr.com/photos/zaragozaantigua/21055742855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25212, 'Pl. de Aragâ”œâ”‚n 1957', 'Imagen en altura del soto de la plaza de Aragâ”œâ”‚n, cuando aâ”œâ•‘n era un espacio provinciano carente de los atractivos que una ciudad moderna debe ofrecer. Unos pocos aâ”œâ–’os despuâ”œÂ®s, se pusieron las cosas en su sitio. Fuente visual: www.delcampe.net', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21526330441.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21526330441.webp', 'https://www.flickr.com/photos/zaragozaantigua/21526330441/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25213, 'Pl. de Aragâ”œâ”‚n 1954', 'Imagen convertida en postal por Ediciones Sicilia, y titulada "Plaza de Aragâ”œâ”‚n y paseo de Independencia". Visual en altura, posiblemente desde el edicicio "Elâ”œÂ¡seos", donde ya se evidencia un colapso circulatorio que sâ”œâ”‚lo podrâ”œÃ­ ser solucionado mediante la necesaria conversiâ”œâ”‚n del paseo en una multiautopista, unos aâ”œâ–’os despuâ”œÂ®s. Y de paso, serâ”œÃ­ posible sustituir la provinciana estampa de hotelitos de la plaza de Aragâ”œâ”‚n, por modernos edificios a la altura de los tiempos, en una ciudad con un glorioso pasado, y un deslumbrante futuro. El trolebâ”œâ•‘s y el tranvâ”œÂ¡a, que parecen como esconderse, no se librarâ”œÃ­n de esta pactada transiciâ”œâ”‚n. Fuente visual: www.delcampe.net/', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64836500, -0.88489400, '0101000020E6100000E7A6CD380D51ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26557498400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26557498400.webp', 'https://www.flickr.com/photos/zaragozaantigua/26557498400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25214, 'Plaza de Aragâ”œâ”‚n c.1962', 'Vista de la plaza de Aragâ”œâ”‚n. Al fondo, edificio Elâ”œÂ¡seos con su peineta, en el chaflâ”œÃ­n entre el paseo del General Mola y el de Calvo Sotelo. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1962, 1962, 1962, 'Anos 60', 'CENTRO', 41.64836500, -0.88489400, '0101000020E6100000E7A6CD380D51ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26813015893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26813015893.webp', 'https://www.flickr.com/photos/zaragozaantigua/26813015893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25215, 'Monumento a Ramâ”œâ”‚n de Pignatelli 1861', 'Glorieta de Pignatelli, con el monumento a Ramâ”œâ”‚n de Pignatelli, obra de Antonio Josâ”œÂ® Palao, inaugurado el 24 de junio de 1859, en conmemoraciâ”œâ”‚n del aniversario del Canal Imperial de Aragâ”œâ”‚n. Al fondo, la Segunda Puerta de Santa Engracia. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œÃ¼lbum de Andrâ”œÂ®s Martâ”œÂ¡n e Ipâ”œÃ­s. Colecciâ”œâ”‚n Mariano Martâ”œÂ¡n Casalderrey. Libro Primeros tiempos de la fotografâ”œÂ¡a en Zaragoza', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88489400, '0101000020E6100000E7A6CD380D51ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28299361240.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28299361240.webp', 'https://www.flickr.com/photos/zaragozaantigua/28299361240/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25216, 'Vista aâ”œÂ®rea plaza Aragâ”œâ”‚n 1957', 'Vista aâ”œÂ®rea de la plaza de Aragâ”œâ”‚n y su entorno. Al fondo, el Pilar. Abajo, la Facultad de Medicina y Ciencias. Fuente: TAF Helicâ”œâ–“pters. Arxiu Nacional de Catalunya.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64839400, -0.88487500, '0101000020E610000037894160E550ECBF19761893FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30988351620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30988351620.webp', 'https://www.flickr.com/photos/zaragozaantigua/30988351620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25217, 'Pl. de Aragâ”œâ”‚n 1955', 'Imagen, capturada desde cierta altura, centrada en la antigua plaza de Aragâ”œâ”‚n. Al fondo, el antiguo paseo de la Independencia. Fuente visual: www.delcampe.es', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64834900, -0.88470100, '0101000020E6100000C2A1B778784FECBF79B29B19FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31063043780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31063043780.webp', 'https://www.flickr.com/photos/zaragozaantigua/31063043780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25220, 'Pl. de Aragâ”œâ”‚n 1957', 'Imagen capturada desde la notable altura del Banco de Crâ”œÂ®dito de Zaragoza, sito al final del paseo de la Independencia, con una interesante panorâ”œÃ­mica centrada en el inmediato entorno de la vecina plaza de Aragâ”œâ”‚n. El Monumento al Justiciazgo hace de eje de esta verde y recoleta glorieta cuya traza todavâ”œÂ¡a recuerda los tiempos en que la figura de Ramâ”œâ”‚n Pignatelli presidâ”œÂ¡a este espacio. Alrededor, los hotelitos de los nâ”œâ•‘meros 6, 7 y 8, a la izquierda; la Capitanâ”œÂ¡a General y el nâ”¬â•‘ 10, a la derecha, donde circula una composiciâ”œâ”‚n de la tranviaria lâ”œÂ¡nea 5. Torrero-Delicias. Mâ”œÃ­s allâ”œÃ­, la plaza de Basilio Paraâ”œÂ¡so, donde transita un trolebâ”œâ•‘s de regreso de la lâ”œÂ¡nea Terminillo, y un coche posiblemente de la lâ”œÂ¡nea del tranvâ”œÂ¡a 15. Casablanca. El Edificio Elâ”œÂ¡seos y la antigua Facultad de Medicina y Ciencias jalonan el arranque de los paseos del General Mola, de Calvo Sotelo, y de Pamplona. A la izquierda y escalonados, los grandes colegios del Salvador, y del Sagrado Corazâ”œâ”‚n de Jesâ”œâ•‘s. Por encima y al fondo, tras el ascenso por las terrazas de Cuâ”œÂ®llar, se destaca la torre del Sacrario Militare Italiano. Fuente visual: AMZ', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64836500, -0.88488200, '0101000020E6100000D6355A0EF450ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47017652142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47017652142.webp', 'https://www.flickr.com/photos/zaragozaantigua/47017652142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25221, 'Pl. de Aragâ”œâ”‚n 1955', 'Al nivel de los peatones, imagen de una luminosa tarde de paseo por la antigua plaza de Aragâ”œâ”‚n, que fuera Glorieta de Pignatelli hasta que a principios del siglo XX las elites locales erigieran el Monumento al Justiciazgo desplazando al ilustrado Pignatelli de esta ubicaciâ”œâ”‚n al ostracismo de la sureâ”œâ–’a periferia, junto a los Depâ”œâ”‚sitos de Agua de la ciudad. Al fondo y a la izquierda, el hotelito del nâ”¬â•‘ 13 de la plaza, recayente a la calle de Josâ”œÂ® Luis Albareda. Tras â”œÂ®l, la monumental manzana del Banco de Crâ”œÂ®dito de Zaragoza, en cuya planta calle el Cafâ”œÂ® Ambos Mundos estaba por cerrarse, tras 74 aâ”œâ–’os desde su inauguraciâ”œâ”‚n. Tras el Justiciazgo, el cenotafio "A los funcionarios muertos en agosto de 1920", y el bulevar del paseo de la Independencia. Fuente visual: AMZ', 1955, 1955, 1955, 'Anos 50', 'CENTRO', 41.64836500, -0.88488200, '0101000020E6100000D6355A0EF450ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47096051531.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47096051531.webp', 'https://www.flickr.com/photos/zaragozaantigua/47096051531/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25222, 'Pl. de Aragâ”œâ”‚n c.1895', 'Inâ”œÂ®dita imagen parcial de la plaza de Aragâ”œâ”‚n capturada desde la altura del inmueble del nâ”¬â•‘ 3, con el fondo edilicio de la Capitanâ”œÂ¡a General, a la izquierda, y el inmueble del nâ”¬â•‘ 10 a la derecha, que destaca por el caracterâ”œÂ¡stico aspecto coronado con cupulines laterales tras la reforma proyectada por Fernando de Yarza. La glorieta sigue presidida por el orondo bulto redondo del prâ”œâ”‚cer Pignatelli rodeado de verjas y exuberante vegetaciâ”œâ”‚n, mirando hacia el sur, hacia el Canal Imperial.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64832800, -0.88477400, '0101000020E61000003E3C4B901150ECBF618A7269FCD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48039751732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48039751732.webp', 'https://www.flickr.com/photos/zaragozaantigua/48039751732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24898, 'Universidad Laboral 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 15/07/1975. En 1967, el Ayuntamiento cediâ”œâ”‚ 200.000 m2 de terreno al Ministerio de Trabajo para la construcciâ”œâ”‚n de una Universidad Laboral Femenina en el barrio de Santa Isabel, a 11 km del centro urbano. En octubre de ese aâ”œâ–’o fue inaugurada, y permaneciâ”œâ”‚ activa hasta 1978, en que desaparecen las Universidades Laborales. En la imagen, actividades deportivas en las instalaciones para la prâ”œÃ­ctica de atletismo.', 1975, 1975, 1975, 'Anos 70', NULL, 41.65257700, -0.79263500, '0101000020E61000005A475513445DE9BF978FA4A487D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15268306596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15268306596.webp', 'https://www.flickr.com/photos/zaragozaantigua/15268306596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25225, 'Plaza de Aragâ”œâ”‚n 1954', 'Imagen capturada en altura desde el Edificio Elâ”œÂ¡seos y centrada en la plaza de Aragâ”œâ”‚n precedida por el antiguo paseo de la Independencia. La arbolada plaza presenta su tradicional estampa de hotelitos, a la izquierda los de los nâ”œâ•‘meros 12 y 13, a la derecha los de los nâ”œâ•‘meros 1, 2 y 8. El bulevar de Independencia arranca de la plaza de Espaâ”œâ–’a donde luce la fachada del Coso recayente a ella. Como telâ”œâ”‚n de fondo emergen, de izquierda a derecha, la torre del reloj del Banco de Aragâ”œâ”‚n, las dos torres sureâ”œâ–’as del Pilar, la câ”œâ•‘pula sobre el torreâ”œâ”‚n del Banco Zaragozano, y la torre y cimborrio de la Seo Esta imagen fue tambiâ”œÂ®n comercializada como postal y por la misma empresa, en una versiâ”œâ”‚n mâ”œÃ­s luminosa y sin recortar por la parte de la derecha y la inferior, donde aparecâ”œÂ¡an un trolebâ”œâ•‘s y un tranvâ”œÂ¡a maniobrando en la linde con la plaza de Basilio Paraâ”œÂ¡so. Esta otra imagen ya la tenemos incorporada en el', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64830400, -0.88489200, '0101000020E6100000BABE0F070951ECBFD9EE1EA0FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48948253206.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48948253206.webp', 'https://www.flickr.com/photos/zaragozaantigua/48948253206/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25226, 'Plaza de Aragâ”œâ”‚n 1950', 'Estupenda imagen capturada en la antigua plaza de Aragâ”œâ”‚n, cuando aâ”œâ•‘n mantenâ”œÂ¡a el espâ”œÂ¡ritu de la original glorieta de Pignatelli, con el valor aâ”œâ–’adido de la frondosa vegetaciâ”œâ”‚n que la caracterizaba, antes de la radical reforma de principios de la siguiente dâ”œÂ®cada. Centra la imagen el Monumento al medieval Justiciazgo que la elite local impuso a la original del prâ”œâ”‚cer ilustrado, desplazado como sus ideas a la lejana periferia sureâ”œâ–’a. Detrâ”œÃ­s y a la izquierda, el rotundo edificio del Banco de Crâ”œÂ®dito de Zaragoza emerge sobre el hotelito del nâ”¬â•‘ 13 de la plaza.', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.64814400, -0.88486000, '0101000020E6100000E23B31EBC550ECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48959425861.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48959425861.webp', 'https://www.flickr.com/photos/zaragozaantigua/48959425861/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25227, 'Plaza de Aragâ”œâ”‚n c.1958', 'Imagen capturada en original blanco y negro junto al Monumento al Justiciazgo sito en la plaza de Aragâ”œâ”‚n, y coloreada posteriormente a mano para ser editada como postal. Hacia el fondo, vista del frondoso bulevar del paseo de la Independencia centrada por el cenotafio "A los funcionarios muertos en agosto de 1920". Esta tradicional zona de paseo y esparcimiento social desaparecerâ”œÂ¡a poco despuâ”œÂ®s en beneficio de la hegemâ”œâ”‚nica circulaciâ”œâ”‚n rodada.', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64854400, -0.88482800, '0101000020E61000000AB952CF8250ECBF2E02637D03D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49137699773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49137699773.webp', 'https://www.flickr.com/photos/zaragozaantigua/49137699773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25228, 'Plaza de Aragâ”œâ”‚n c.1954', 'Imagen capturada desde la altura del antiguo inmueble del nâ”¬â•‘ 8 de la plaza de Aragâ”œâ”‚n, con una vista del inmediato espacio arbolado de la plaza centrado desde 1904 por el Monumento al Justiciazgo. El entorno edilicio seguâ”œÂ¡a definido por la planta de los decimonâ”œâ”‚nicos hotelitos, alguno recrecido recientemente, como el del nâ”¬â•‘ 12, a la izquierda de la escena. Hacia el fondo, el bulevar que conformaba el antiguo paseo de la Independencia. En primer tâ”œÂ®rmino y a la derecha, circula una unidad de la serie 200 en servicio en la lâ”œÂ¡nea 11. Parque, que sigue a una composiciâ”œâ”‚n de la lâ”œÂ¡nea 5. Venecia-Delicias, ambas encaminadas hacia la plaza de Espaâ”œâ–’a.', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64836800, -0.88476400, '0101000020E61000005BB39597FC4FECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49273387833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49273387833.webp', 'https://www.flickr.com/photos/zaragozaantigua/49273387833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25232, 'Glorieta de Pignatelli 1878', 'Imagen capturada por el fotâ”œâ”‚grafo villanovense Gregorio Sabatâ”œÂ® Fâ”œÂ®rriz e integrada en el â”œÃ­lbum "Vistas de Zaragoza", que se centra en este gran bulto redondo del orondo Ramâ”œâ”‚n Pignatelli Moncayo Inaugurado en 1859 como elemento central del escenario donde tuvo lugar la Primera Exposiciâ”œâ”‚n Aragonesa entre setiembre y noviembre de 1868, ubicada en el novâ”œÂ¡simo recinto del Salâ”œâ”‚n de Pignatelli que antes fuera denominado Prado de San Jerâ”œâ”‚nimo. A pesar de que el Palacio de la Exposiciâ”œâ”‚n, el edificio principal de la misma, habâ”œÂ¡a sido erigido con la intenciâ”œâ”‚n de que permaneciera y fuera el pionero de una pronta urbanizaciâ”œâ”‚n de esta zona, pero la penuria econâ”œâ”‚mica municipal hizo que fuera derribado para vender el suelo que ocupaba, aunque el proceloso proceso de urbanizaciâ”œâ”‚n se extenderâ”œÂ¡a hasta entrado el siglo XX, marcado siempre por los intereses particulares de los propietarios del suelo que fueron construyendo sus respectivos "hotelitos" al ritmo que mejor les pareciâ”œâ”‚. En la imagen, la estatua dedicada a Pignatelli en el despejado entorno de la arbolada glorieta a la que daba nombre. Tras la estatua rodeada de verja y a la izquierda, espacio donde pronto serâ”œÂ¡a construido el primero de los "hotelitos" de la glorieta. A la derecha, edificios del lado de los pares de la calle de la Independencia que se proyectan hacia la plaza de la Constituciâ”œâ”‚n, comenzando con el reciente Teatro de Novedades.', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64814400, -0.88510700, '0101000020E6100000D3BD4EEACB52ECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54751914094.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54751914094.webp', 'https://www.flickr.com/photos/zaragozaantigua/54751914094/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25257, 'Vista paseo Pamplona c.1900', 'Vista de Zaragoza y sus torres desde la Facultad de Medicina y Ciencias. En primer plano, paseo de la Lealtad, luego de Pamplona. En el centro, ante el cuartel de Artillerâ”œÂ¡a del Carmen, la iglesia de las Esclavas del Sagrado Corazâ”œâ”‚n, en la esquina de la calle de Teruel (luego de Bilbao) con la de Canfranc. Fuente: Foto Alday, en www.kutxateka.eus/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64893400, -0.88630900, '0101000020E61000009AD024B1A45CECBF98A1F14410D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37971354276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37971354276.webp', 'https://www.flickr.com/photos/zaragozaantigua/37971354276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
